import{_ as e,o as l,c as a,a2 as n}from"./chunks/framework.Pywvta2k.js";const f=JSON.parse('{"title":"妇科跨医家索引","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/06-跨病证索引/04-妇科.md","filePath":"tcm-data/06-跨病证索引/04-妇科.md","lastUpdated":1781084559000}'),s={name:"tcm-data/06-跨病证索引/04-妇科.md"};function d(i,t,r,g,o,h){return l(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="妇科跨医家索引" tabindex="-1">妇科跨医家索引 <a class="header-anchor" href="#妇科跨医家索引" aria-label="Permalink to &quot;妇科跨医家索引&quot;">​</a></h1><blockquote><p>妇科各病证在不同医家手中的认识与治法</p></blockquote><hr><h2 id="一、月经先期-核心症状" tabindex="-1">一、月经先期（核心症状） <a class="header-anchor" href="#一、月经先期-核心症状" aria-label="Permalink to &quot;一、月经先期（核心症状）&quot;">​</a></h2><h3 id="跨医家对比" tabindex="-1">跨医家对比 <a class="header-anchor" href="#跨医家对比" aria-label="Permalink to &quot;跨医家对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">病机</th><th style="text-align:left;">治法</th><th style="text-align:left;">代表方</th><th style="text-align:left;">适合患者（女）？</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>傅青主</strong></td><td style="text-align:left;">血热（量多）或阴虚（量少）</td><td style="text-align:left;">清热或滋阴</td><td style="text-align:left;">清经散/两地汤</td><td style="text-align:left;">✅ 部分匹配</td></tr><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">冲任虚寒（伴瘀血）</td><td style="text-align:left;">温经散寒</td><td style="text-align:left;">温经汤</td><td style="text-align:left;">⚠️ 患者（女）有热象</td></tr><tr><td style="text-align:left;"><strong>朱震亨</strong></td><td style="text-align:left;">相火妄动</td><td style="text-align:left;">滋阴降火</td><td style="text-align:left;">大补阴丸</td><td style="text-align:left;">⚠️ 偏寒凉</td></tr><tr><td style="text-align:left;"><strong>李辛</strong></td><td style="text-align:left;">下焦封藏不住</td><td style="text-align:left;">补肾固摄</td><td style="text-align:left;">熟地+山萸+杜仲</td><td style="text-align:left;">✅ 部分匹配</td></tr><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">木郁化火，疏泄太过</td><td style="text-align:left;">达木清风</td><td style="text-align:left;">桂枝+白芍+丹皮</td><td style="text-align:left;">✅ 部分匹配</td></tr></tbody></table><h3 id="患者-女-月经先期的辨证" tabindex="-1">患者（女）月经先期的辨证 <a class="header-anchor" href="#患者-女-月经先期的辨证" aria-label="Permalink to &quot;患者（女）月经先期的辨证&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>症状：23-25天周期，量色正常，伴烦躁、目疲劳、腰凉</span></span>
<span class="line"><span>辨证：肝郁血虚为本，郁而化热为标，下焦不固为底</span></span>
<span class="line"><span>治则：养血疏郁为主，清热固经为辅</span></span>
<span class="line"><span>代表方：加减黄芽地魄汤（当归+白芍+熟地+柴胡+杜仲）</span></span></code></pre></div><hr><h2 id="二、带下病-相关" tabindex="-1">二、带下病（相关） <a class="header-anchor" href="#二、带下病-相关" aria-label="Permalink to &quot;二、带下病（相关）&quot;">​</a></h2><h3 id="跨医家对比-1" tabindex="-1">跨医家对比 <a class="header-anchor" href="#跨医家对比-1" aria-label="Permalink to &quot;跨医家对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">病机</th><th style="text-align:left;">治法</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>傅青主</strong></td><td style="text-align:left;">脾虚湿盛（白带）</td><td style="text-align:left;">健脾祛湿</td><td style="text-align:left;"><strong>完带汤</strong></td></tr><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">寒湿或湿热</td><td style="text-align:left;">温化或清利</td><td style="text-align:left;">当归芍药散</td></tr><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">土湿木郁，湿浊下注</td><td style="text-align:left;">泄湿燥土</td><td style="text-align:left;">茯苓+泽泻+黄柏</td></tr></tbody></table><h3 id="患者-女-白带辨证" tabindex="-1">患者（女）白带辨证 <a class="header-anchor" href="#患者-女-白带辨证" aria-label="Permalink to &quot;患者（女）白带辨证&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>症状：量多、色白偏微黄、无异味</span></span>
<span class="line"><span>辨证：脾虚湿盛为主，兼有下焦郁热</span></span>
<span class="line"><span>治则：健脾燥湿为主，少佐清热</span></span>
<span class="line"><span>建议：完带汤思路，但加少量黄柏</span></span>
<span class="line"><span>患者处方中白术+茯苓已覆盖此需求</span></span></code></pre></div><hr><h2 id="三、妊娠病" tabindex="-1">三、妊娠病 <a class="header-anchor" href="#三、妊娠病" aria-label="Permalink to &quot;三、妊娠病&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">治法特点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">桂枝汤为妊娠第一方，当归散常服养胎</td></tr><tr><td style="text-align:left;"><strong>傅青主</strong></td><td style="text-align:left;">顺气安胎为主，保产无忧散</td></tr></tbody></table><hr><h2 id="四、产后病" tabindex="-1">四、产后病 <a class="header-anchor" href="#四、产后病" aria-label="Permalink to &quot;四、产后病&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">治法</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">新产三病（痉、郁冒、大便难）</td><td style="text-align:left;">竹叶汤、小柴胡汤</td></tr><tr><td style="text-align:left;"><strong>傅青主</strong></td><td style="text-align:left;">「产后大补气血为先」</td><td style="text-align:left;">生化汤</td></tr><tr><td style="text-align:left;"><strong>李可</strong></td><td style="text-align:left;">产后虚寒多，温补为要</td><td style="text-align:left;">四逆汤加味</td></tr></tbody></table><hr><h2 id="五、虚劳-围绝经期" tabindex="-1">五、虚劳（围绝经期） <a class="header-anchor" href="#五、虚劳-围绝经期" aria-label="Permalink to &quot;五、虚劳（围绝经期）&quot;">​</a></h2><h3 id="跨医家对比-2" tabindex="-1">跨医家对比 <a class="header-anchor" href="#跨医家对比-2" aria-label="Permalink to &quot;跨医家对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">医家</th><th style="text-align:left;">病机</th><th style="text-align:left;">治法</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>张仲景</strong></td><td style="text-align:left;">虚劳里急，阴阳两虚</td><td style="text-align:left;">建中</td><td style="text-align:left;">小建中汤、黄芪建中汤</td></tr><tr><td style="text-align:left;"><strong>黄元御</strong></td><td style="text-align:left;">水寒土湿，肝脾不升</td><td style="text-align:left;">温阳达木</td><td style="text-align:left;">天魂汤、乌肝汤</td></tr><tr><td style="text-align:left;"><strong>李辛</strong></td><td style="text-align:left;">能量不足，开阖失序</td><td style="text-align:left;">培中+补肾+收敛</td><td style="text-align:left;">补中+潜降</td></tr><tr><td style="text-align:left;"><strong>张介宾</strong></td><td style="text-align:left;">命门火衰或真阴不足</td><td style="text-align:left;">温补</td><td style="text-align:left;">左归丸或右归丸</td></tr></tbody></table><hr><p><em>本索引可在后续扩展到更年期专题、妇科肿瘤的中医治疗等内容。</em></p>`,26)])])}const y=e(s,[["render",d]]);export{f as __pageData,y as default};
